import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import '../styles/login.css';
import { pushToast } from '../utils/toastBridge'

export const Login = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const error = null;
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(true);

  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    pushToast({ title: 'Thất bại', message: '', type: 'error' });
    setLoading(true);

    if (!username || !password) {
      pushToast({ title: 'Thất bại', message: 'Vui lÃ²ng nháº­p tÃªn Ä‘Äƒng nháº­p vÃ  máº­t kháº©u', type: 'error' });
      setLoading(false);
      return;
    }

    const result = await login(username, password);
    setLoading(false);

    if (result.success) {
      // Redirect Ä‘áº¿n dashboard dá»±a trÃªn role
      const role = String(result.user?.role || '').trim().toUpperCase();
      if (role === 'ADMIN') {
        navigate('/admin/dashboard');
      } else if (role === 'OWNER') {
        navigate('/owner/dashboard');
      } else if (role === 'MANAGER') {
        navigate('/manager/dashboard');
      } else if (role === 'ACCOUNTANT') {
        navigate('/accountant/dashboard');
      } else if (role === 'WORKER') {
        navigate('/worker/dashboard');
      } else if (role === 'TECHNICIAN') {
        navigate('/technician/dashboard');
      } else if (role === 'STOREKEEPER') {
        navigate('/storekeeper/dashboard');
      } else {
        navigate('/');
      }
    } else {
      pushToast({ title: 'Thất bại', message: result.message, type: 'error' });
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-layout">
        <div className="center-panel">
          <div className="form-card form-card--large">
            <div className="auth-brand-mark">
              <div className="auth-brand-mark__icon">ðŸ¦</div>
            </div>
            <form onSubmit={handleSubmit} className="auth-form">
              <h2>ÄÄƒng nháº­p</h2>
              <p className="auth-form__subtitle">Há»‡ thá»‘ng quáº£n lÃ½ ao tÃ´m thÃ´ng minh</p>

              <div className="form-group">
                <label htmlFor="username">TÃªn Ä‘Äƒng nháº­p</label>
                <input
                  id="username"
                  type="text"
                  className="auth-text-input"
                  placeholder="Nháº­p tÃªn Ä‘Äƒng nháº­p hoáº·c email"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  disabled={loading}
                  required
                />
              </div>

              <div className="form-group">
                <label htmlFor="password">Máº­t kháº©u</label>
                <div className="password-input-wrapper">
                  <input
                    id="password"
                    type={showPassword ? 'text' : 'password'}
                    placeholder="Nháº­p máº­t kháº©u"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    disabled={loading}
                    required
                  />
                  <button
                    type="button"
                    className="password-toggle"
                    onClick={() => setShowPassword(!showPassword)}
                    tabIndex="-1"
                  >
                    {showPassword ? 'ðŸ‘ï¸â€ðŸ—¨ï¸' : 'ðŸ‘ï¸'}
                  </button>
                </div>
              </div>

              <div className="auth-options-row">
                <label className="auth-remember">
                  <input
                    type="checkbox"
                    checked={rememberMe}
                    onChange={(e) => setRememberMe(e.target.checked)}
                  />
                  <span>Ghi nhá»› Ä‘Äƒng nháº­p</span>
                </label>
                <span className="auth-forgot">QuÃªn máº­t kháº©u?</span>
              </div>

              <button type="submit" className="btn btn-primary btn-block" disabled={loading}>
                {loading ? 'ðŸ”„ Äang Ä‘Äƒng nháº­p...' : 'ðŸ”’ ÄÄƒng nháº­p'}
              </button>
            </form>

            <div className="auth-footer">
              <p>
                ChÆ°a cÃ³ tÃ i khoáº£n?{' '}
                <Link to="/register" className="auth-link">
                  ÄÄƒng kÃ½ ngay
                </Link>
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
